  'ganzhou/house': ('Nhà thổ lâu Khách Gia', 'Văn hóa Khách Gia đã tồn tại hàng thế kỷ trong những ngôi nhà pháo đài hình tròn độc đáo.'),
  'ganzhou/pavilion': ('Úc Cô Đài', 'Từng được các thi sĩ thời Tống ca ngợi, đài ngắm cảnh này nhìn ra nơi giao thoa của dòng sông.'),
  'ganzhou/star': ('Vạn lý Trường chinh', 'Cuộc Vạn lý Trường chinh lịch sử của Hồng quân đã bắt đầu từ chính thành phố này.'),
  'putian/shrine': ('Đền thờ Mẫu Tổ', 'Nữ thần Mẫu Tổ, vị thần bảo hộ ngư dân, đã sinh ra tại đây và ngôi đền thờ chính của bà nằm trên đảo Mi Châu.'),
  'putian/lychee': ('Vườn vải', 'Những cây vải nghìn năm tuổi đã mang lại cho thành phố này danh hiệu \'vùng đất của vải thiều\'.'),
  'putian/shoe': ('Thủ phủ giày dép', 'Một phần lớn sản lượng giày thể thao trên thế giới được sản xuất từ các xưởng tại đây.'),
  'putian/wave': ('Đảo Mi Châu', 'Hòn đảo này nổi tiếng với những bãi biển thơ mộng và các lễ hội đền chùa đặc sắc, có thể di chuyển đến bằng phà.'),
  'mudanjiang/snow': ('Làng Tuyết', 'Ngôi làng tựa như trong truyện cổ tích với những lớp tuyết dày bao phủ, tỏa sáng rực rỡ vào mùa đông.'),
  'mudanjiang/lake': ('Hồ Kính Bạc', 'Đây là một hồ nước chắn ngang do núi lửa tạo thành, nơi có thác nước Điếu Thủy Lâu vẫn chảy mạnh mẽ ngay cả trong mùa đông.'),
  'mudanjiang/tiger': ('Công viên Hổ Siberia', 'Đây là một trong những khu bảo tồn hổ Siberia lớn nhất trên thế giới.'),
  'mudanjiang/ski': ('Mùa trượt tuyết', 'Mùa đông dài với tuyết phủ dày đặc đã đưa khu vực này trở thành điểm đến không thể bỏ qua của những người yêu thích trượt tuyết.'),
  'changzhou/dino': ('Công viên Khủng long', 'Công viên chủ đề về khủng long nổi tiếng nhất Trung Quốc này là biểu tượng du lịch gia đình của thành phố.'),
  'changzhou/pagoda': ('Chùa Thiên Ninh', 'Với chiều cao 153 mét, đây là ngôi chùa cao nhất thế giới nằm ngay trung tâm thành phố.'),
  'changzhou/comb': ('Nghề làm lược', 'Những chiếc lược Thường Châu với lịch sử hàng nghìn năm từng là món quà quý giá được dâng lên cung đình.'),
  'changzhou/canal': ('Đại Vận Hà', 'Dọc theo bờ kênh là nơi lý tưởng để tản bộ, ngắm nhìn những khu phố cổ và ánh đèn đêm lung linh.'),
  'shaoxing/wine': ('Rượu Thiệu Hưng', 'Loại rượu gạo vàng nổi tiếng trong ẩm thực Trung Hoa này đã được ủ tại đây suốt hàng thiên niên kỷ.'),
  'shaoxing/bridge': ('Cầu đá cổ', 'Với hệ thống kênh rạch chằng chịt, Thiệu Hưng hiện vẫn lưu giữ hàng trăm cây cầu đá hình vòm cổ kính.'),
  'shaoxing/pen': ('Cái nôi thư pháp', 'Đình Lan Đình của bậc thầy Vương Hy Chi được coi là thánh địa của nghệ thuật thư pháp.'),
  'shaoxing/boat': ('Thuyền Ô Bồng', 'Những chiếc thuyền Ô Bồng được chèo bằng chân là phương tiện di chuyển cổ điển trên các con kênh tại đây.'),
  'bengbu/shell': ('Cảng Ngọc Trai', 'Tên gọi của thành phố có nghĩa là \'bến hàu\', nơi từng nổi tiếng với những viên ngọc trai quý giá từ sông Hoài.'),
  'bengbu/train': ('Cửa ngõ đường sắt', 'Thành phố này phát triển mạnh mẽ nhờ vị trí là điểm giao cắt quan trọng của tuyến đường sắt Bắc - Nam qua sông Hoài.'),
  'bengbu/river': ('Sông Hoài', 'Đây chính là dòng sông được coi là ranh giới tự nhiên phân chia miền Bắc và miền Nam Trung Quốc.'),
  'bengbu/blossom': ('Hội hoa xuân', 'Mỗi độ xuân về, các công viên ven sông lại rực rỡ sắc hoa trong những lễ hội truyền thống.'),
  'jiujiang/mountain': ('Lư Sơn', 'Những đỉnh núi mờ sương của Lư Sơn, di sản thế giới UNESCO, đã trở thành nguồn cảm hứng bất tận cho biết bao thi nhân và họa sĩ.'),
  'jiujiang/tea': ('Trà Vân Vụ', 'Loại trà Vân Vụ trồng trên sườn núi Lư Sơn được mệnh danh là một trong những loại trà tinh tế nhất Trung Quốc.'),
  'jiujiang/lake': ('Hồ Bà Dương', 'Hồ nước ngọt lớn nhất Trung Quốc này là nơi cư ngụ của hàng ngàn con sếu mỗi khi mùa đông tới.'),
  'jiujiang/scroll': ('Thành phố thi ca', 'Cửa ngõ ven sông này từng là nơi lưu dấu những vần thơ bất hủ của các đại thi hào như Bạch Cư Dị và Tô Thức.'),
  'quanzhou/ship': ('Con đường tơ lụa trên biển', 'Từng được Marco Polo gọi là \'Zayton\', đây là cảng biển sầm uất nhất thế giới thời trung cổ và hiện là di sản UNESCO.'),
  'quanzhou/mosque': ('Thánh đường Thanh Tịnh', 'Được xây dựng từ năm 1009, đây là một trong những thánh đường Hồi giáo cổ xưa nhất tại Trung Quốc.'),
  'quanzhou/puppet': ('Múa rối dây', 'Nghệ thuật múa rối dây Tuyền Châu là một truyền thống sân khấu lâu đời đã tồn tại hàng ngàn năm.'),
  'quanzhou/tea': ('Trà Thiết Quan Âm', 'Loại trà ô long trứ danh từ vùng An Khê lân cận được thế giới biết đến với cái tên \'Nữ thần sắt\'.'),
  'shanghai/pearl': ('Tháp truyền hình Minh Châu Phương Đông', 'Với những khối cầu màu hồng vươn cao bên dòng Hoàng Phố, tòa tháp này là biểu tượng hiện đại của Thượng Hải.'),
  'shanghai/bund': ('Bến Thượng Hải', 'Dãy kiến trúc lịch sử dọc bờ sông phản chiếu vẻ đẹp huy hoàng của Thượng Hải thời xưa.'),
  'shanghai/garden': ('Dự Viên', 'Khu vườn cổ thời nhà Minh với những hòn non bộ và hồ nước tĩnh lặng là ốc đảo bình yên giữa lòng thành phố.'),
  'shanghai/xlb': ('Tiểu long bao', 'Những chiếc bánh bao hấp chứa đầy nước dùng nóng hổi là món điểm tâm tinh túy nhất của ẩm thực Thượng Hải.'),
  'hangzhou/lake': ('Tây Hồ', 'Với những hàng liễu, đảo nhỏ và cầu vòm, đây là hồ nước được ca ngợi nhiều nhất trong thi ca Trung Hoa.'),
  'hangzhou/tea': ('Trà Long Tỉnh', 'Được trồng trên các sườn đồi quanh hồ, loại trà xanh \'Giếng Rồng\' này là danh trà nổi tiếng nhất Trung Quốc.'),
  'hangzhou/temple': ('Chùa Linh Ẩn', 'Ngôi chùa 1.700 năm tuổi này nổi tiếng với các tác phẩm chạm khắc đá tinh xảo và tượng Phật khổng lồ.'),
  'hangzhou/silk': ('Phố lụa Hàng Châu', 'Lụa Hàng Châu đã được dệt suốt hàng ngàn năm, tạo nên sự thịnh vượng cho điểm cuối phía đông của Con đường Tơ lụa.'),
  'chongqing/hongya': ('Hồng Nhai Động', 'Tổ hợp nhà sàn rực rỡ bám vào vách đá, tỏa sáng như một tòa lâu đài cổ tích bên bờ sông khi đêm về.'),
  'chongqing/hotpot': ('Lẩu Trùng Khánh', 'Với hương vị cay nồng từ dầu ớt và tê từ hạt tiêu, lẩu chính là linh hồn ẩm thực của thành phố núi này.'),
  'chongqing/monorail': ('Đường sắt trên cao Trùng Khánh', 'Tuyến đường sắt chạy xuyên qua tòa nhà chung cư là hình ảnh biểu tượng độc đáo của thành phố địa hình đồi núi này.'),
  'chongqing/river': ('Tam Hiệp Trường Giang', 'Các chuyến du thuyền Tam Hiệp khởi hành từ cảng này, nơi thành phố vươn mình tại điểm giao thoa của hai dòng sông lớn.'),
  'dalian/square': ('Quảng trường Tinh Hải', 'Đây là quảng trường thành phố lớn nhất châu Á, nơi diễn ra nhiều lễ hội và sự kiện sôi động bên bờ biển.'),
  'dalian/beach': ('Bãi biển Đại Liên', 'Với những vịnh đá và mùa hè mát mẻ, Đại Liên là khu nghỉ dưỡng ven biển được yêu thích nhất ở miền Bắc Trung Quốc.'),
  'dalian/football': ('Thành phố bóng đá', 'Được mệnh danh là \'cái nôi của bóng đá Trung Quốc\', đây là nơi sản sinh ra những câu lạc bộ giàu thành tích nhất cả nước.'),
  'dalian/seafood': ('Hải sản Đại Liên', 'Các loại sò điệp, tôm và nhím biển từ vùng biển Hoàng Hải lạnh giá luôn là món ngon đặc sắc trên bàn ăn của thành phố.'),
  'shenyang/palace': ('Thẩm Dương Cố Cung', 'Đây là cung điện đầu tiên của nhà Thanh, được xem như người anh em nhỏ hơn của Tử Cấm Thành ở Bắc Kinh.'),
  'shenyang/tomb': ('Lăng mộ nhà Thanh', 'Các khu lăng mộ phía Đông và phía Bắc bao quanh thành phố là những công trình tưởng niệm hoành tráng của các vị hoàng đế khai quốc nhà Thanh.'),
  'shenyang/factory': ('Cái nôi công nghiệp', 'Ngành công nghiệp nặng của Trung Quốc khởi nguồn từ đây, với những nhà máy khổng lồ giúp thành phố được mệnh danh là \'vùng Ruhr của phương Đông\'.'),
  'shenyang/dumpling': ('Sủi cảo Lão Biên', 'Món sủi cảo hấp Lão Biên với lịch sử hơn 200 năm là đặc sản trứ danh trên bàn tiệc phương Bắc.'),
  'hefei/judge': ('Bao Công Từ', 'Là quê hương của vị quan thanh liêm Bao Chửng, ngôi đền này chính là biểu tượng cho sự chính trực.'),
  'hefei/science': ('Thành phố Khoa học', 'Đây là trung tâm công nghệ quy tụ nhiều trường đại học và phòng thí nghiệm hàng đầu của Trung Quốc.'),
  'hefei/lake': ('Hồ Sào', 'Một trong năm hồ nước ngọt lớn nhất Trung Quốc, nổi tiếng với đặc sản cá trắng và cua.'),
  'hefei/cake': ('Bánh vừng Lư Châu', 'Món bánh vừng nhân ngọt là thức quà truyền thống lâu đời của vùng đất Lư Châu xưa.'),
  'foshan/wingchun': ('Vịnh Xuân Quyền', 'Đây là cái nôi của võ thuật Vịnh Xuân, nơi khởi nguồn của những huyền thoại như Diệp Vấn và Lý Tiểu Long.'),
  'foshan/lion': ('Múa lân', 'Được mệnh danh là thủ phủ của múa lân phương Nam, nơi những chú lân rực rỡ sắc màu nhảy múa trên các cột cao trong lễ hội.'),
  'foshan/ceramic': ('Gốm Thạch Loan', 'Những lò gốm nghìn năm tuổi vẫn ngày đêm nung nấu nên các bức tượng gốm Thạch Loan đầy sống động.'),
  'foshan/opera': ('Kịch Quảng Đông', 'Vùng đất này chính là nơi nghệ thuật sân khấu được yêu thích nhất miền Nam Trung Quốc phát triển rực rỡ.'),
  'guiyang/pavilion': ('Giáp Tú Các', 'Tòa lầu ba tầng nằm bên dòng sông Nam Minh này đã trở thành biểu tượng của thành phố suốt 400 năm qua.'),
  'guiyang/sourfish': ('Cá nấu canh chua', 'Món cá nấu trong nước dùng cà chua lên men có vị chua thanh đặc trưng là món ăn tiêu biểu của Quý Châu.'),
  'guiyang/waterfall': ('Thác Hoàng Quả Thụ', 'Một trong những thác nước lớn nhất châu Á đổ xuống ầm ầm, tạo nên những dải cầu vồng rực rỡ.'),
  'guiyang/miao': ('Văn hóa người Miêu', 'Những lễ hội và nghề thêu thùa của người dân tộc Miêu với trang phục đội vương miện bạc đã tô điểm cho các bản làng miền núi.'),
  'changchun/film': ('Thành phố Điện ảnh', 'Nơi đây được mệnh danh là \'Hollywood của phương Đông\', cái nôi khai sinh ra nền điện ảnh Trung Quốc.'),
  'changchun/car': ('Thành phố Ô tô', 'Đây là thủ phủ ô tô của cả nước, nơi những chiếc xe hơi đầu tiên do Trung Quốc tự sản xuất đã ra đời.'),
  'changchun/palace': ('Ngụy Mãn Hoàng cung', 'Nơi ở của vị hoàng đế cuối cùng là nhân chứng thầm lặng cho một giai đoạn lịch sử đầy biến động.'),
  'changchun/snow': ('Tuyết mùa đông', 'Suốt mùa đông dài trắng xóa, thành phố bừng sáng với những tác phẩm điêu khắc băng và các đường trượt tuyết.'),
  'xining/lake': ('Hồ Thanh Hải', 'Hồ nước mặn lớn nhất Trung Quốc nổi tiếng với những cánh đồng hoa cải vàng rực rỡ bao quanh vào mùa hè.'),
  'xining/monastery': ('Tu viện Kumbum', 'Một trong sáu tu viện lớn nhất của Phật giáo Tây Tạng, nổi danh với các tác phẩm điêu khắc từ bơ bò yak.'),
  'xining/flower': ('Hoa cải dầu', 'Vào tháng Bảy, cả cao nguyên như được phủ một tấm thảm vàng óng của những cánh đồng hoa cải trải dài đến tận chân trời.'),
  'xining/lamb': ('Thịt bò yak và thịt cừu', 'Mì kéo tay và thịt cừu xiên nướng mang đậm hương vị ẩm thực của người Hồi và người Tây Tạng trên vùng cao nguyên.'),
  'guilin/karst': ('Núi đá vôi sông Ly', 'Những đỉnh núi đá vôi nhô lên từ làn sương mờ ảo chính là khung cảnh được in trên tờ tiền 20 nhân dân tệ.'),
  'guilin/elephant': ('Núi Vòi Voi', 'Tảng đá có hình dáng như chú voi đang cúi vòi xuống dòng sông là biểu tượng yêu quý của thành phố.'),
  'guilin/terrace': ('Ruộng bậc thang Long Tích', 'Những thửa ruộng bậc thang \'Sống lưng rồng\' uốn lượn quanh sườn núi là minh chứng cho hàng thế kỷ lao động miệt mài.'),
  'guilin/osmanthus': ('Hoa mộc tê', 'Tên gọi của thành phố có nghĩa là \'rừng hoa mộc\', nơi mỗi độ thu về lại ngập tràn hương thơm ngọt ngào của loài hoa này.'),
  'wenzhou/merchant': ('Tinh thần thương nhân', 'Được mệnh danh là \'người Do Thái của Trung Quốc\', các doanh nhân Ôn Châu đã xây dựng mạng lưới kinh doanh trên khắp toàn cầu.'),
  'wenzhou/shoe': ('Giày da', 'Một phần lớn sản lượng giày da trên thế giới được sản xuất từ thành phố công nghiệp này.'),
  'wenzhou/mountain': ('Núi Nhạn Đãng', 'Nổi tiếng với những thác nước và đỉnh núi hiểm trở, nơi đây được ca ngợi là \'đệ nhất sơn bên bờ biển\'.'),
  'wenzhou/seafood': ('Hải sản', 'Mực, sò điệp và các loại cá từ biển Hoa Đông là nguyên liệu chủ đạo trong các bữa ăn của người dân địa phương.'),
  'tangshan/memorial': ('Đài tưởng niệm động đất', 'Công viên tưởng niệm trận động đất lịch sử năm 1976 là biểu tượng cho sự hồi sinh mạnh mẽ của thành phố.'),
  'tangshan/coal': ('Than đá và thép', 'Đây là cái nôi của ngành công nghiệp hiện đại Trung Quốc, nơi khai thác mỏ than và tuyến đường sắt đầu tiên của quốc gia.'),
  'tangshan/ceramic': ('Gốm sứ Đường Sơn', 'Được mệnh danh là \'thành phố gốm sứ phương Bắc\', các sản phẩm sứ xương tại đây luôn nổi tiếng với vẻ đẹp tinh tế.'),
  'tangshan/lake': ('Công viên Nam Hồ', 'Khu công viên hồ nước này vốn được cải tạo từ một hố mỏ cũ, nay đã trở thành lá phổi xanh của thành phố.'),
  'anshan/steel': ('Thành phố thép', 'Nơi đây là \'thủ phủ thép\' của Trung Quốc, đồng thời là địa điểm đặt nhà máy luyện thép lớn nhất cả nước.'),
  'anshan/jade': ('Ngọc Tú Nham', 'Thành phố này được coi là vùng đất ngọc của Trung Quốc, nơi lưu giữ tác phẩm điêu khắc bằng ngọc lớn nhất thế giới.'),
  'anshan/mountain': ('Núi Thiên Sơn', 'Với những ngôi chùa cổ và vách đá hùng vĩ, \'Thiên Sơn\' được coi là ngọn núi thiêng của vùng Đông Bắc.'),
  'anshan/spring': ('Suối nước nóng Đường Cương Tử', 'Suối nước nóng này đã nổi tiếng từ hàng ngàn năm trước với công dụng chữa bệnh và từng là nơi nghỉ dưỡng của các bậc hoàng đế.'),
  'linyi/market': ('Chợ bán buôn', 'Đây là trung tâm bán buôn lớn nhất miền Bắc Trung Quốc, chuyên phân phối hàng hóa đi khắp cả nước.'),
  'linyi/brush': ('Thánh thư pháp', 'Lâm Nghi là quê hương của Vương Hy Chi - \'thánh thư pháp\' của Trung Quốc, nơi được mệnh danh là vùng đất của mực và bút.'),
  'linyi/mountain': ('Núi Mông Sơn', 'Là ngọn núi cao thứ hai ở Sơn Đông, nơi đây được ví như \'quán bar oxy\' với không khí trong lành và những thác nước tuyệt đẹp.'),
  'linyi/pancake': ('Bánh xèo Nghi Mông', 'Món bánh xèo mỏng làm từ ngô là món ăn truyền thống lâu đời của người dân vùng núi Nghi Mông.'),
  'cangzhou/lion': ('Sư tử sắt', 'Tượng sư tử đúc bằng sắt khổng lồ có niên đại hơn 1.100 năm tuổi này là biểu tượng đầy tự hào của thành phố.'),
  'cangzhou/martial': ('Võ thuật', 'Thương Châu được mệnh danh là \'quê hương của võ thuật\' Trung Quốc, nơi sản sinh ra nhiều võ sư và võ đường nổi tiếng.'),
  'cangzhou/canal': ('Đại Vận Hà', 'Kênh đào Đại Vận Hà Bắc Kinh - Hàng Châu chảy qua thành phố, nơi vẫn còn lưu giữ những bến tàu cổ kính.'),
  'cangzhou/jujube': ('Táo tàu vàng', 'Loại táo tàu \'tơ vàng\' với lớp vỏ mỏng và vị ngọt thanh được mệnh danh là vua của các loại trái cây sấy khô.'),
  'nantong/textile': ('Thành phố Dệt may', 'Được mệnh danh là thủ phủ dệt may của Trung Quốc, các sản phẩm vải bông tại đây đã vươn tầm ra thị trường thế giới.'),
  'nantong/mountain': ('Núi Lang', 'Ngọn núi thiêng với năm đỉnh nhấp nhô nằm ngay cửa sông Dương Tử là điểm đến hành hương và ngắm cảnh nổi tiếng.'),
  'nantong/kite': ('Diều sáo', 'Những chiếc diều sáo \'banyao\' với âm thanh vi vu đặc trưng là một loại hình thủ công truyền thống lâu đời của thành phố.'),
  'nantong/school': ('Tiên phong giáo dục', 'Nhà công nghiệp Trương Kiên đã thành lập những ngôi trường hiện đại và bảo tàng đầu tiên của Trung Quốc tại nơi này.'),
  'taizhou/opera': ('Mai Lan Phương', 'Đây là quê hương của Mai Lan Phương, bậc thầy huyền thoại của nghệ thuật Kinh kịch.'),
  'taizhou/tea': ('Trà sáng', 'Thưởng thức trà sáng cùng các loại bánh bao hấp đã trở thành một nghi thức ẩm thực không thể thiếu của người dân nơi đây.'),
  'taizhou/boat': ('Lễ hội đua thuyền Côn Đồng', 'Vào mùa xuân, lễ hội với hàng trăm tay chèo tranh tài đã mang lại sức sống mãnh liệt cho dòng sông.'),
  'taizhou/meatball': ('Thịt viên đầu sư tử', 'Món thịt viên mềm mịn, thơm ngon này là một tuyệt phẩm kinh điển của nền ẩm thực Hoài Dương.'),
  'jinhua/ham': ('Giăm bông Kim Hoa', 'Được chế biến bằng phương pháp truyền thống hàng thế kỷ, đây là loại giăm bông nổi tiếng nhất tại Trung Quốc.'),
  'jinhua/film': ('Phim trường Hoành Điếm', 'Đây là phim trường ngoài trời lớn nhất thế giới, nơi ghi hình cho vô số bộ phim cổ trang nổi tiếng.'),
  'jinhua/cave': ('Động Song Long', 'Du khách sẽ được trải nghiệm cảm giác choáng ngợp khi đi thuyền qua cửa hang đá thấp để tiến vào hang động ngầm kỳ vĩ này.'),
  'jinhua/bridge': ('Cầu cổ', 'Những cây cầu đá vòm cùng các thị trấn ven sông mang đậm nét duyên dáng đặc trưng của vùng Giang Nam.'),
  'wuhu/park': ('Công viên giải trí Phương Đặc', 'Là một trong những công viên giải trí lớn nhất Trung Quốc, nơi đây mang đến cho các gia đình những ngày vui chơi đầy phấn khích.'),
  'wuhu/ironart': ('Tranh sắt', 'Những bức tranh sắt tinh xảo được rèn từ sắt uốn là một loại hình nghệ thuật thủ công có lịch sử 300 năm.'),
  'wuhu/rice': ('Cảng gạo', 'Nằm bên bờ sông Dương Tử, thành phố này từng là thị trường kinh doanh gạo lớn nhất Trung Quốc trong lịch sử.'),
  'wuhu/river': ('Cảng Dương Tử', 'Đây là một cảng sông sầm uất, đóng vai trò là cửa ngõ thông ra biển của tỉnh An Huy.'),
  'huangshan/peak': ('Hoàng Sơn', 'Với những đỉnh núi đá granite, biển mây bồng bềnh và những cây thông cổ thụ, đây là ngọn núi nổi tiếng nhất Trung Quốc.'),
  'huangshan/village': ('Thôn Hoành', 'Ngôi làng cổ với những bức tường trắng soi bóng bên dòng nước này đã được UNESCO công nhận là di sản thế giới và đẹp tựa như một bức tranh thủy mặc.'),
  'huangshan/tea': ('Trà Mao Phong', 'Được hái trên những sườn núi mờ sương, loại trà xanh với những búp non phủ lông tơ này là một trong mười loại trà danh tiếng nhất Trung Quốc.'),
  'huangshan/ink': ('Mực và Nghệ thuật Huy Châu', 'Mực Huy Châu, những ngôi nhà gỗ chạm khắc tinh xảo và nghệ thuật thư pháp chính là kho tàng văn hóa quý giá của vùng đất này.'),
  'yichun/moon': ('Núi Minh Nguyệt', 'Ngọn núi \'Trăng Sáng\' này nổi tiếng với các suối nước nóng và hệ thống cáp treo ngắm cảnh tuyệt đẹp.'),
  'yichun/spring': ('Suối nước nóng', 'Nguồn suối nước nóng giàu selen quý hiếm đã biến thành phố này thành trung tâm tắm khoáng hàng đầu Trung Quốc.'),
  'yichun/zen': ('Thiền tông', 'Những ngôi chùa cổ nằm sâu trong núi, nơi khởi nguồn của các tông phái Thiền tông Trung Hoa, mang đến không gian tĩnh lặng tuyệt đối.'),
  'yichun/rice': ('Đồng bằng lúa gạo', 'Đồng bằng Viên-Hà màu mỡ từ lâu đã được coi là vựa lúa của tỉnh Giang Tây.'),
  'zhangzhou/narcissus': ('Hoa thủy tiên', 'Đây là nơi trồng hoa thủy tiên nổi tiếng nhất Trung Quốc, loài hoa biểu tượng cho các dịp lễ hội mùa xuân.'),
  'zhangzhou/tulou': ('Thổ lâu', 'Những pháo đài bằng đất nện hình tròn khổng lồ này đã được UNESCO công nhận, nơi cả một ngôi làng cùng chung sống dưới một mái nhà.'),
  'zhangzhou/banana': ('Trái cây nhiệt đới', 'Những vườn chuối, nhãn và quýt giúp vùng đồng bằng ấm áp này luôn xanh tươi quanh năm.'),
  'zhangzhou/coast': ('Đảo Đông Sơn', 'Với những bãi biển vàng óng và các làng chài yên bình, hòn đảo này được ví như viên ngọc quý của vùng duyên hải phía Nam.'),
  'beijing/great-wall': ('Vạn Lý Trường Thành', 'Đây là công trình phòng thủ dài nhất thế giới với hơn 20.000 km được xây dựng qua nhiều thế kỷ để bảo vệ biên giới phía Bắc, trong đó đoạn Bát Đạt Lĩnh gần Bắc Kinh là nơi thu hút nhiều du khách nhất.'),
  'beijing/temple': ('Thiên Đàn', 'Đây là khu phức hợp linh thiêng nơi các hoàng đế nhà Minh và nhà Thanh từng đến cầu nguyện cho mùa màng bội thu, nổi tiếng với kiến trúc mái vòm ba tầng màu xanh không dùng một chiếc đinh nào.'),
  'beijing/pagoda': ('Chùa Thiên Ninh', 'Đây là ngôi chùa gạch 13 tầng cao khoảng 57 mét có từ thời nhà Liêu, một trong những công trình cổ nhất còn sót lại tại Bắc Kinh chứng kiến lịch sử ngàn năm của thành phố.'),
  'beijing/opera': ('Kinh kịch', 'Loại hình nghệ thuật truyền thống 200 năm tuổi này kết hợp giữa ca hát, đối thoại, võ thuật và nhào lộn, trong đó các kiểu vẽ mặt (liên phổ) giúp khán giả nhận diện tính cách nhân vật như màu đỏ tượng trưng cho lòng trung thành và màu trắng cho sự gian xảo.'),
};
